import { Focusable } from '@earendil-works/pi-tui';
import { Theme, ExtensionContext } from '@earendil-works/pi-coding-agent';

/** A single action item in the prompt dialog. */
interface PromptAction<TAction extends string = string> {
    /** Unique identifier for this action (e.g. "exit", "cancel"). */
    id: TAction;
    /** Human-readable label shown in the menu. */
    label: string;
    /** Whether this action is the default (Enter key immediately selects it). */
    default?: boolean;
}
/** Configuration for the optional inline input field. */
interface PromptInput {
    /** Label shown before the input field (e.g. "补充指令"). */
    label: string;
    /** Placeholder text shown when input is empty. */
    placeholder?: string;
}
/** Options passed to showPromptDialog(). */
interface PromptDialogOptions<TAction extends string = string> {
    /** Title shown at the top of the dialog. */
    title: string;
    /** Optional multi-line description / context (e.g. the blocked command). */
    description?: string;
    /** List of actions (1-10 items). */
    actions: PromptAction<TAction>[];
    /** Optional inline input field. When omitted, no input row is shown. */
    input?: PromptInput;
}
/** Discriminated union returned by showPromptDialog(). */
type PromptDialogResult<TAction extends string = string> = {
    type: "action";
    action: TAction;
} | {
    type: "input";
    value: string;
} | undefined;
declare function validateOptions<TAction extends string>(options: PromptDialogOptions<TAction>): void;

declare class PromptDialogComponent<TAction extends string> implements Focusable {
    readonly width = 70;
    /** Focusable interface — set by TUI when focus changes */
    focused: boolean;
    private selected;
    private actions;
    private inputConfig;
    private inputText;
    private inputCursor;
    private inputFocused;
    private title;
    private description;
    private theme;
    private done;
    /** Total navigation items: actions + (optional) input row */
    private get itemCount();
    constructor(options: PromptDialogOptions<TAction>, theme: Theme, done: (result: PromptDialogResult<TAction>) => void);
    handleInput(data: string): void;
    render(_width: number): string[];
    invalidate(): void;
    dispose(): void;
}

/**
 * Show a customizable prompt dialog overlay in pi's interactive TUI.
 *
 * The dialog displays a title, optional description, a list of actions (with
 * keyboard navigation), and an optional inline text input. It returns a
 * discriminated union so callers can narrow the result easily.
 *
 * @example
 * ```ts
 * const result = await showPromptDialog(ctx, {
 *   title: "Plan 模式拦截了此操作",
 *   description: "agent 想跑：npm install lodash",
 *   actions: [
 *     { id: "exit", label: "退出并执行", default: true },
 *     { id: "cancel", label: "取消" },
 *   ],
 *   input: { label: "补充指令", placeholder: "想让我怎么做？" },
 * });
 *
 * if (!result) {
 *   // Esc pressed
 * } else if (result.type === "action") {
 *   console.log("user chose:", result.action); // "exit" | "cancel"
 * } else {
 *   console.log("user typed:", result.value);
 * }
 * ```
 */
declare function showPromptDialog<TAction extends string>(ctx: ExtensionContext, options: PromptDialogOptions<TAction>): Promise<PromptDialogResult<TAction>>;

export { type PromptAction, PromptDialogComponent, type PromptDialogOptions, type PromptDialogResult, type PromptInput, showPromptDialog, validateOptions };
